function getHeader(headers, name) {
  const h = headers?.find(h => (h.name || '').toLowerCase() === name.toLowerCase());
  return h ? h.value : '';
}

function decodeBase64Url(data) {
  if (!data) return '';
  const normalized = data.replace(/-/g, '+').replace(/_/g, '/');
  return Buffer.from(normalized, 'base64').toString('utf8');
}

function extractPart(payload, mimeType) {
  if (!payload) return '';

  if (payload.mimeType === mimeType && payload.body?.data) {
    return decodeBase64Url(payload.body.data);
  }

  if (payload.parts && Array.isArray(payload.parts)) {
    for (const part of payload.parts) {
      if (part.mimeType === mimeType && part.body?.data) {
        return decodeBase64Url(part.body.data);
      }
    }
    for (const part of payload.parts) {
      if (part.parts) {
        const nested = extractPart(part, mimeType);
        if (nested) return nested;
      }
    }
  }

  return '';
}

function stripHtml(html) {
  return (html || '')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+\n/g, '\n')
    .replace(/\n\s+/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .trim();
}

return items.map(item => {
  const j = item.json;
  const payload = j.payload || {};
  const headers = payload.headers || [];

  const from = getHeader(headers, 'From');
  const to = getHeader(headers, 'To');
  const subject = getHeader(headers, 'Subject');
  const date = getHeader(headers, 'Date');
  const messageIdHeader = getHeader(headers, 'Message-ID');

  let bodyText = extractPart(payload, 'text/plain');
  if (!bodyText) {
    const html = extractPart(payload, 'text/html');
    bodyText = stripHtml(html);
  }
  if (!bodyText) bodyText = j.snippet || '';

  return {
    json: {
      gmail_message_id: j.id,
      gmail_thread_id: j.threadId,
      message_id_header: messageIdHeader,
      from_email: from,
      to_email: to,
      subject: subject,
      received_at: date,
      snippet: j.snippet || '',
      body_text: bodyText.trim(),
      status: 'new'
    }
  };
});

